import{_ as t,o,c as i,ag as a}from"./chunks/framework.DLWhSH9p.js";const h=JSON.parse('{"title":"Feedback","description":"","frontmatter":{},"headers":[],"relativePath":"guide/feedback.md","filePath":"guide/feedback.md"}'),n={name:"guide/feedback.md"};function s(r,e,l,d,c,u){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="feedback" tabindex="-1">Feedback <a class="header-anchor" href="#feedback" aria-label="Permalink to &quot;Feedback&quot;">​</a></h1><p>The Feedback panel lets you submit suggestions, bug reports, and content ideas that get refined by AI and posted as GitHub Issues.</p><h2 id="opening-the-panel" tabindex="-1">Opening the Panel <a class="header-anchor" href="#opening-the-panel" aria-label="Permalink to &quot;Opening the Panel&quot;">​</a></h2><p>Click <strong>Feedback</strong> in the top chrome&#39;s right rail (visible when a GitHub token is configured — see <a href="/guide/ai-providers.html">AI providers</a>).</p><h2 id="submitting-feedback" tabindex="-1">Submitting Feedback <a class="header-anchor" href="#submitting-feedback" aria-label="Permalink to &quot;Submitting Feedback&quot;">​</a></h2><ol><li><strong>Title</strong> -- a brief summary of your feedback</li><li><strong>Description</strong> -- detailed explanation of the suggestion, bug, or idea</li><li><strong>Channel</strong> (optional) -- associate the feedback with a specific channel for context</li></ol><h2 id="ai-grooming" tabindex="-1">AI Grooming <a class="header-anchor" href="#ai-grooming" aria-label="Permalink to &quot;AI Grooming&quot;">​</a></h2><p>Click <strong>Groom with AI</strong> to have the local Ollama model analyze and refine your feedback. The AI returns:</p><ul><li><strong>Refined Title</strong> -- a clearer, more actionable version</li><li><strong>Summary</strong> -- 1-2 sentence distillation</li><li><strong>Action Items</strong> -- concrete checklist of things to do</li><li><strong>Labels</strong> -- categorization tags (e.g., &quot;bug&quot;, &quot;feature&quot;, &quot;content-idea&quot;)</li><li><strong>Priority</strong> -- low, medium, or high based on impact</li><li><strong>Suggestions</strong> -- tips to improve or expand the feedback</li></ul><p>All fields are editable after grooming -- tweak anything before submitting.</p><h2 id="submitting-to-github" tabindex="-1">Submitting to GitHub <a class="header-anchor" href="#submitting-to-github" aria-label="Permalink to &quot;Submitting to GitHub&quot;">​</a></h2><p>Click <strong>Submit to GitHub</strong> to create an issue in the <a href="https://github.com/Mossworks-Labs/craft" target="_blank" rel="noreferrer">Mossworks-Labs/craft</a> repository.</p><div class="warning custom-block"><p class="custom-block-title">GITHUB_TOKEN Required</p><p>The &quot;Submit to GitHub&quot; button is only visible when a <code>GITHUB_TOKEN</code> is configured. The panel checks <code>GET /api/keys</code> on mount to detect this. If no token is found, a hint appears explaining how to add one via the API Keys modal or <code>GITHUB_TOKEN</code> in <code>app/.env</code>.</p></div><p>The issue includes:</p><ul><li>Refined title as the issue title</li><li>Markdown body with summary, action items checklist, original description, suggestions, and metadata</li><li>Labels from the groomed result plus a <code>feedback</code> label</li><li>Your username so the issue is attributed to you</li></ul><p>The submission runs as an async background job. You&#39;ll see real-time status updates and a link to the created issue once complete.</p><div class="info custom-block"><p class="custom-block-title">Requirements</p><ul><li><strong>Ollama</strong> must be running for AI grooming. Enable GPU services via Helm (<code>gpu.enabled: true</code> in values.yaml) or <code>docker compose -f docker-compose.dev.yml --profile gpu up -d</code> for local dev.</li><li><strong>GitHub Token</strong> required for issue submission — add via API Keys modal or <code>GITHUB_TOKEN</code> in <code>app/.env</code></li></ul></div><h2 id="re-grooming" tabindex="-1">Re-grooming <a class="header-anchor" href="#re-grooming" aria-label="Permalink to &quot;Re-grooming&quot;">​</a></h2><p>Click <strong>Re-groom</strong> to run the AI analysis again with your edited fields. This is useful if you&#39;ve substantially changed the description after the first grooming pass.</p>',19)])])}const b=t(n,[["render",s]]);export{h as __pageData,b as default};
